using Microsoft.EntityFrameworkCore;
class ProductContext : DbContext
{
    public DbSet<Product> Products => Set<Product>();
    protected override void OnModelCreating(ModelBuilder modelBuilder)
    {
        modelBuilder.Entity<Product>(entity =>
        {
            entity.ToContainer("Products");

            // EF Core 9 breaking change #1: Discriminator property renamed from
            // "Discriminator" to "$type". Existing 500K documents use "Discriminator",
            // so we must preserve the old property name for data compatibility.
            entity.HasDiscriminator<string>("Discriminator");

            // EF Core 9 breaking change #2: Id format changed from "EntityType|Key"
            // (e.g. "Product|123") to just the raw key value ("123").
            // Existing documents use the old format, so opt back in to it.
            entity.HasPartitionKey(p => p.Id);
            entity.Property(p => p.Id)
                  .ToJsonPropertyName("id")
                  .HasValueGenerator<Microsoft.EntityFrameworkCore.Cosmos.ValueGeneration.IdValueGenerator>();
        });
    }

    protected override void ConfigureConventions(ModelConfigurationBuilder configurationBuilder)
    {
        // EF Core 9 breaking change #3: Sync APIs (ToList, First, Single, etc.)
        // are no longer supported by the Cosmos provider; use async equivalents.
        // No code-level opt-in exists — callers must migrate to async APIs.
    }
}
class Product { public int Id { get; set; } public string Sku { get; set; } }

