class CosmosQuery
{
    async Task FindProductsAsync(ProductContext ctx)
    {
        // Direct Cosmos SQL — safe to keep referencing c.Discriminator because we
        // configured HasDiscriminator("Discriminator") in OnModelCreating.
        // Without that override, EF Core 9 would write "$type" instead and this
        // query would silently return zero results against existing documents.
        var sql = "SELECT * FROM c WHERE c.Discriminator = 'Product' AND c.Sku = @sku";

        // EF Core 9 breaking change #3: Cosmos provider removed sync APIs.
        // ToList() → ToListAsync(), First() → FirstAsync(), etc.
        var products = await ctx.Products.Where(p => p.Sku == "ABC").ToListAsync();
    }
}

