            // (e.g. "Product|123") to just the raw key value ("123").
            // Existing documents use the old "Product|123" format, so we keep the
            // legacy format by explicitly opting in to the old id value generator.
            entity.Property(p => p.Id)
                  .HasValueGenerator(
